import { Injectable, signal, computed, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, of } from 'rxjs';
import { tap, map, catchError } from 'rxjs/operators';
import { environment } from '../../../environments/environment';
import { User, Role } from '../models';

const TOKEN_KEY = 'token';
const USER_KEY = 'user';

interface AuthResponse {
  token: string;
  user: User;
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;
  private http = inject(HttpClient);
  private router = inject(Router);

  private _user = signal<User | null>(this.readStoredUser());

  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._user());
  readonly isAdmin = computed(() => this._user()?.role === 'admin');

  private readStoredUser(): User | null {
    try {
      const raw = localStorage.getItem(USER_KEY);
      return raw ? (JSON.parse(raw) as User) : null;
    } catch {
      return null;
    }
  }

  private persist(token: string, user: User): void {
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem('access_token', token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    localStorage.setItem('isAuthenticated', 'true');
    this._user.set(user);
  }

  /** Real login endpoint. In the mockup, falls back to a local session so the form stays usable offline. */
  login(email: string, password: string): Observable<User> {
    return this.http.post<AuthResponse>(`${this.apiUrl}/auth/login`, { email, password }).pipe(
      tap((res) => this.persist(res.token, res.user)),
      map((res) => res.user),
      catchError(() => {
        const role: Role = email.startsWith('admin') ? 'admin' : 'shopper';
        const user: User = { id: 'local', email, name: email.split('@')[0], role };
        this.persist('demo-token', user);
        return of(user);
      }),
    );
  }

  /** Real signup endpoint (shopper accounts). Falls back to a local session in the mockup. */
  signup(name: string, email: string, password: string): Observable<User> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/register`, { name, email, password })
      .pipe(
        tap((res) => this.persist(res.token, res.user)),
        map((res) => res.user),
        catchError(() => {
          const user: User = { id: 'local', email, name, role: 'shopper' };
          this.persist('demo-token', user);
          return of(user);
        }),
      );
  }

  /** Demo Mode bypass — signs in as a seeded admin and jumps into the authenticated app. */
  demoLogin(): void {
    const user: User = { id: 'demo-admin', email: 'admin@demo', name: 'Demo Admin', role: 'admin' };
    this.persist('demo-admin-token', user);
    this.router.navigate(['/admin/products']);
  }

  /** Demo Mode bypass — signs in as a seeded shopper. */
  demoLoginShopper(): void {
    const user: User = { id: 'demo-shopper', email: 'shopper@demo', name: 'Demo Shopper', role: 'shopper' };
    this.persist('demo-shopper-token', user);
    this.router.navigate(['/']);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem('access_token');
    localStorage.removeItem(USER_KEY);
    localStorage.removeItem('isAuthenticated');
    this._user.set(null);
    this.router.navigate(['/login']);
  }
}
